// Import required libraries
const ethers = require('ethers');
const express = require('express');

// Set up Express app
const app = express();
app.use(express.json());

// Set up wallet and provider
const wallet = new ethers.Wallet(process.env.PRIVATE_KEY, ethers.getDefaultProvider());
const contractAddress = '0x...'; // Replace with your contract address

// Define a function to validate user input
function validateInput(input) {
  if (typeof input !== 'object') return false;
  for (const key in input) {
    if (!['from', 'to', 'value'].includes(key)) return false;
  }
  return true;
}

// Define a function to construct and send transactions
async function sendTransaction(txParams) {
  try {
    const tx = await wallet.sendTransaction({
      from: txParams.from,
      to: contractAddress,
      value: ethers.utils.parseEther(txParams.value.toString()),
      gasLimit: '20000',
      gasPrice: ethers.utils.parseUnits('20', 'gwei'),
    });
    return tx.hash;
  } catch (error) {
    console.error(error);
    throw error;
  }
}

// Define a route to handle user input
app.post('/send-transaction', async (req, res) => {
  const txParams = req.body;
  if (!validateInput(txParams)) {
    return res.status(400).json({ message: 'Invalid transaction parameters' });
  }

  try {
    const txHash = await sendTransaction(txParams);
    res.json({ message: `Transaction sent with hash ${txHash}` });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Error sending transaction' });
  }
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});